#include <iostream>
using namespace std;
int main()
{
    int a,b,d=0;
    cin>>a>>b;
    int c[a];
    for(int i=0;i<a;i++)
        {
            cin>>c[i];
        }
    for(int i=0;i<b;i++)
        {
            for(int j=0;j<a-1-i;j++)
                {
                    if(c[j]>c[j+1])
                    {
                        d=c[j+1];
                        c[j+1]=c[j];
                        c[j]=d;
                    }
                }
        }
    cout<<c[b];
    return 0;
}
